const benefits = [
  {
    icon: '⚖',
    title: 'Assurance obligatoire',
    description: 'L\'assurance décennale est obligatoire pour tout électricien selon la loi Spinetta (1978).'
  },
  {
    icon: '🛡',
    title: 'Protection 10 ans',
    description: 'Notre garantie décennale vous protège pendant 10 ans après la fin de vos chantier.'
  },
  {
    icon: '📋',
    title: 'RC Pro incluse',
    description: 'La Responsabilité Civile Professionnelle est incluse dans toutes nos offres.'
  },
  {
    icon: '⚡',
    title: 'Sinistres couverts',
    description: 'Tous types de travaux électriques couverts : installation, domotique, IRVE.'
  }
];

export default function Benefits() {
  return (
    <section className="py-12 md:py-20 bg-white">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-10 md:mb-14">
          <h2 className="text-2xl sm:text-3xl md:text-4xl font-bold text-gray-900">
            Pourquoi choisir <span className="text-blue-800">Décennale Pro</span> ?
          </h2>
          <p className="mt-3 sm:mt-4 text-gray-600 text-base md:text-lg max-w-2xl mx-auto">
            Nous simplifions l'assurance de votre activité d'électricien avec un service adapté à vos besoins.
          </p>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6">
          {benefits.map((benefit, index) => (
            <div 
              key={index} 
              className="card text-center group hover:-translate-y-1"
            >
              <div className="w-12 h-12 sm:w-14 sm:h-14 bg-blue-100 rounded-2xl flex items-center justify-center mx-auto mb-3 sm:mb-4 group-hover:bg-gray-100 transition-colors">
                <span className="text-2xl sm:text-3xl">{benefit.icon}</span>
              </div>
              <h3 className="text-lg sm:text-xl font-bold text-gray-900 mb-2 sm:mb-3">{benefit.title}</h3>
              <p className="text-gray-600 text-sm sm:text-base">{benefit.description}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
